solution_code:
#include <iostream>
#include <string>

int main()
{
    std::string word{};
    std::cin >> word;

    int start{};
    int length{};
    std::cin >> start >> length;

    std::string sub{ word.substr(static_cast<std::size_t>(start),
                                 static_cast<std::size_t>(length)) };
    std::cout << sub << '\n';
    std::cout << sub.length() << '\n';

    return 0;
}

